"""
Parameterized generator for GH726_diesel_4986.

Source PR:    https://github.com/diesel-rs/diesel/pull/4986
Source Issue: N/A

Seed varies: renames 'action' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH726_diesel_4986'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH726_diesel_4986'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('action', 'action' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH726_diesel_4986',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'diesel-rs/diesel',
                "pr_number": 4986,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/diesel-rs/diesel/pull/4986",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/workflows/ci.yml': 'on:\n  merge_group:\n    types: [checks_requested]\n  pull_request:\n    types: [opened, synchronize, reopened]\n  push:\n    branches:\n      - main\n      - "0.[0-9]+.x"\n      - "1.[0-9]+.x"\n      - "2.[0-9]+.x"\n\nname: CI Tests\npermissions:\n  contents: "read"\n  actions: "write"\n\n# See: https://docs.github.com/en/actions/reference/workflow-syntax-for-github-actions#concurrency.\n# This will ensure that only one commit will be running tests at a time on each PR.\nconcurrency:\n  group: ${{ github.ref }}-${{ github.workflow }}\n  cancel-in-progress: true\n\njobs:\n  check_and_test:\n    name: Check\n    needs: [rustfmt_and_clippy]\n    strategy:\n      fail-fast: false\n      matrix:\n        rust: ["stable"]\n        backend: ["postgres", "sqlite", "mysql"]\n        os:\n          [\n            ubuntu-latest,\n            macos-15-intel,\n            macos-15,\n            windows-2025,\n            ubuntu-24.04-arm,\n          ]\n        include:\n          - rust: "beta"\n            backend: "postgres"\n            os: "ubuntu-latest"\n          - rust: "beta"\n            backend: "sqlite"\n            os: "ubuntu-latest"\n          - rust: "beta"\n            backend: "mysql"\n            os: "ubuntu-latest"\n          - rust: "nightly"\n            backend: "postgres"\n            os: "ubuntu-latest"\n          - rust: "nightly"\n            backend: "sqlite"\n            os: "ubuntu-latest"\n          - rust: "nightly"\n            backend: "mysql"\n            os: "ubuntu-latest"\n    runs-on: ${{ matrix.os }}\n    steps:\n      - name: Checkout sources\n        uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: ${{ matrix.os }}-${{ matrix.backend }}-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n\n      - name: Set environment variables\n        shell: bash\n        if: matrix.rust == \'nightly\'\n        run: |\n          echo "RUSTDOCFLAGS=--cfg doc_cfg" >> $GITHUB_ENV\n\n      - name: Set environment variables\n        shell: bash\n        if: matrix.rust != \'nightly\'\n        run: |\n          echo "RUSTFLAGS=-D warnings" >> $GITHUB_ENV\n          echo "RUSTDOCFLAGS=-D warnings" >> $GITHUB_ENV\n\n      - name: Install postgres (Linux)\n        if: runner.os == \'Linux\' && matrix.backend == \'postgres\'\n        run: |\n          sudo apt-get update\n          sudo apt-get install -y libpq-dev postgresql\n          sudo service postgresql restart && sleep 3\n          sudo -u postgres psql -c "ALTER USER postgres PASSWORD \'postgres\';"\n          sudo service postgresql restart && sleep 3\n          echo "PG_DATABASE_URL=postgres://postgres:postgres@localhost/" >> $GITHUB_ENV\n          echo "PG_EXAMPLE_DATABASE_URL=postgres://postgres:postgres@localhost/diesel_example" >> $GITHUB_ENV\n\n      - name: Install sqlite (Linux)\n        if: runner.os == \'Linux\' && matrix.backend == \'sqlite\'\n        run: |\n          sudo apt-get update\n          sudo apt-get install -y libsqlite3-dev\n          echo "SQLITE_DATABASE_URL=/tmp/test.db" >> $GITHUB_ENV\n\n      - name: Install mysql (Linux)\n        if: runner.os == \'Linux\' && matrix.backend == \'mysql\'\n        run: |\n          sudo apt-get update\n          sudo apt-get install -y libtirpc-dev\n          sudo systemctl start mysql.service\n          mysql -e "create database diesel_test; create database diesel_unit_test; grant all on \\`diesel_%\\`.* to \'root\'@\'localhost\';" -uroot -proot\n          echo "MYSQL_DATABASE_URL=mysql://root:root@127.0.0.1/diesel_test" >> $GITHUB_ENV\n          echo "MYSQL_EXAMPLE_DATABASE_URL=mysql://root:root@127.0.0.1/diesel_example" >> $GITHUB_ENV\n          echo "MYSQL_UNIT_TEST_DATABASE_URL=mysql://root:root@127.0.0.1/diesel_unit_test" >> $GITHUB_ENV\n\n      - name: Install postgres (MacOS)\n        if: runner.os == \'macOS\' && matrix.backend == \'postgres\'\n        run: |\n          brew update\n          brew install postgresql@14\n          brew services start postgresql@14\n          sleep 3\n          createuser -s postgres\n          echo "PG_DATABASE_URL=postgres://postgres@localhost/" >> $GITHUB_ENV\n\n      - name: Install sqlite (MacOS)\n        if: runner.os == \'macOS\' && matrix.backend == \'sqlite\'\n        run: |\n          # otherwise brew install fails\n          HOMEBREW_NO_INSTALLED_DEPENDENTS_CHECK=1 brew install sqlite\n          echo "SQLITE_DATABASE_URL=/tmp/test.db" >> $GITHUB_ENV\n\n      - name: Install mysql (MacOS Intel)\n        if: matrix.os == \'macos-15-intel\' && matrix.backend == \'mysql\'\n        run: |\n          brew install mysql@8.4\n          /usr/local/opt/mysql@8.4/bin/mysql.server start\n          sleep 3\n          /usr/local/opt/mysql@8.4/bin/mysql -e "create database diesel_test; create database diesel_unit_test;  grant all on \\`diesel_%\\`.* to \'root\'@\'localhost\';" -uroot\n          echo "MYSQL_DATABASE_URL=mysql://root@127.0.0.1/diesel_test" >> $GITHUB_ENV\n          echo "MYSQL_EXAMPLE_DATABASE_URL=mysql://root@127.0.0.1/diesel_example" >> $GITHUB_ENV\n          echo "MYSQL_UNIT_TEST_DATABASE_URL=mysql://root@127.0.0.1/diesel_unit_test" >> $GITHUB_ENV\n          echo "MYSQLCLIENT_LIB_DIR=/usr/local/opt/mysql@8.4/lib" >> $GITHUB_ENV\n          echo "MYSQLCLIENT_VERSION=8.4" >> $GITHUB_ENV\n\n      - name: Install mysql (MacOS M1)\n        if: matrix.os == \'macos-15\' && matrix.backend == \'mysql\'\n        run: |\n          brew install mysql@8.4\n          ls /opt/homebrew/opt/mysql@8.4\n          /opt/homebrew/opt/mysql@8.4/bin/mysql.server start\n          sleep 3\n          /opt/homebrew/opt/mysql@8.4/bin/mysql -e "create database diesel_test; create database diesel_unit_test; grant all on \\`diesel_%\\`.* to \'root\'@\'localhost\';" -uroot\n          echo "MYSQL_DATABASE_URL=mysql://root@127.0.0.1/diesel_test" >> $GITHUB_ENV\n          echo "MYSQL_EXAMPLE_DATABASE_URL=mysql://root@l127.0.0.1/diesel_example" >> $GITHUB_ENV\n          echo "MYSQL_UNIT_TEST_DATABASE_URL=mysql://root@127.0.0.1/diesel_unit_test" >> $GITHUB_ENV\n          echo "MYSQLCLIENT_LIB_DIR=/opt/homebrew/opt/mysql@8.4/lib" >> $GITHUB_ENV\n          echo "MYSQLCLIENT_VERSION=8.4" >> $GITHUB_ENV\n\n      - name: Install sqlite (Windows)\n        if: runner.os == \'Windows\' && matrix.backend == \'sqlite\'\n        shell: cmd\n        run: |\n          choco install sqlite\n          cd /D C:\\ProgramData\\chocolatey\\lib\\SQLite\\tools\n          call "C:\\Program Files\\Microsoft Visual Studio\\2022\\Enterprise\\VC\\Auxiliary\\Build\\vcvars64.bat"\n          lib /machine:x64 /def:sqlite3.def /out:sqlite3.lib\n\n      - name: Set variables for sqlite (Windows)\n        if: runner.os == \'Windows\' && matrix.backend == \'sqlite\'\n        shell: bash\n        run: |\n          echo "C:\\ProgramData\\chocolatey\\lib\\SQLite\\tools" >> $GITHUB_PATH\n          echo "SQLITE3_LIB_DIR=C:\\ProgramData\\chocolatey\\lib\\SQLite\\tools" >> $GITHUB_ENV\n          echo "SQLITE_DATABASE_URL=C:\\test.db" >> $GITHUB_ENV\n\n      - name: Install postgres (Windows)\n        if: runner.os == \'Windows\' && matrix.backend == \'postgres\'\n        shell: bash\n        run: |\n          choco install postgresql14 --force --params \'/Password:root\'\n          echo "OPENSSL_RUST_USE_NASM=0" >> $GITHUB_ENV\n          echo OPENSSL_SRC_PERL=C:/Strawberry/perl/bin/perl >> $GITHUB_ENV\n          echo "PQ_LIB_DIR=C:\\Program Files\\PostgreSQL\\14\\lib" >> $GITHUB_ENV\n          echo "PG_DATABASE_URL=postgres://postgres:root@localhost/" >> $GITHUB_ENV\n          echo "PG_EXAMPLE_DATABASE_URL=postgres://postgres:root@localhost/diesel_example" >> $GITHUB_ENV\n\n      - name: Install mysql (Windows)\n        if: runner.os == \'Windows\' && matrix.backend == \'mysql\'\n        shell: bash\n        run: |\n          mkdir "C:\\\\Program Files\\\\MySQL\\\\MySQL Server 8.0\\\\data\\\\"\n          "C:\\\\Program Files\\\\MySQL\\MySQL Server 8.0\\\\bin\\\\mysqld" --console --initialize --initialize-insecure\n          "C:\\\\Program Files\\\\MySQL\\MySQL Server 8.0\\\\bin\\\\mysqld" --console &\n          sleep 15\n          "C:\\\\Program Files\\\\MySQL\\\\MySQL Server 8.0\\\\bin\\\\mysql" -e "create database diesel_test;" -u root\n          "C:\\\\Program Files\\\\MySQL\\\\MySQL Server 8.0\\\\bin\\\\mysql" -e "create database diesel_unit_test;" -u root\n          "C:\\\\Program Files\\\\MySQL\\\\MySQL Server 8.0\\\\bin\\\\mysql" -e \'grant all on `diesel_%`.* to \'root\'@\'localhost\';\' -uroot\n          # remove doxygen because mysqlclient build otherwise breaks?\n          rm "C:/Strawberry/c/bin/doxygen.exe"\n          echo "OPENSSL_RUST_USE_NASM=0" >> $GITHUB_ENV\n          echo OPENSSL_SRC_PERL=C:/Strawberry/perl/bin/perl >> $GITHUB_ENV\n          echo "MYSQL_DATABASE_URL=mysql://root@127.0.0.1/diesel_test" >> $GITHUB_ENV\n          echo "MYSQL_EXAMPLE_DATABASE_URL=mysql://root@127.0.0.1/diesel_example" >> $GITHUB_ENV\n          echo "MYSQL_UNIT_TEST_DATABASE_URL=mysql://root@127.0.0.1/diesel_unit_test" >> $GITHUB_ENV\n          echo "MYSQLCLIENT_LIB_DIR=C:\\Program Files\\MySQL\\MySQL Server 8.0\\lib" >> $GITHUB_ENV\n          echo "MYSQLCLIENT_VERSION=8.0.40" >> $GITHUB_ENV\n          echo "C:\\Program Files\\MySQL\\MySQL Server 8.0\\lib" >> $GITHUB_PATH\n          echo "C:\\Program Files\\MySQL\\MySQL Server 8.0\\bin" >> $GITHUB_PATH\n          dir "C:\\Program Files\\MySQL\\MySQL Server 8.0\\lib"\n\n      - name: Install rust toolchain\n        uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: ${{ matrix.rust }}\n          components: rustfmt\n\n      - name: Rust version check\n        shell: bash\n        run: |\n          rustup override set ${{ matrix.rust }}\n          cargo --version\n          rustc --version\n\n      - uses: taiki-e/install-action@60581cd7025e0e855cebd745379013e286d9c787 # v2.64.2\n        with:\n          tool: nextest\n\n      - name: Add Flags (nightly)\n        if: matrix.rust == \'nightly\'\n        shell: bash\n        run: |\n          echo FLAGS="-F diesel/i-implement-a-third-party-backend-and-opt-into-breaking-changes -F diesel/unstable -F diesel/without-deprecated" >> $GITHUB_ENV\n\n      - name: Add Flags (beta + Sqlite)\n        if: matrix.rust == \'beta\' && matrix.backend == \'sqlite\'\n        shell: bash\n        run: |\n          echo FLAGS="-F diesel/returning_clauses_for_sqlite_3_35 -F libsqlite3-sys/bundled" >> $GITHUB_ENV\n\n      - name: Add Flags (beta)\n        if: matrix.rust == \'beta\'\n        shell: bash\n        run: |\n          echo FLAGS="${FLAGS} -F diesel/time -F diesel/chrono -F diesel/numeric -F diesel/extras -F diesel_derives/time -F diesel_derives/chrono -F diesel_derives/numeric"\n\n      - name: Add Flags (stable)\n        if: matrix.rust == \'stable\'\n        shell: bash\n        run: |\n          echo FLAGS="-F diesel/with-deprecated" >> $GITHUB_ENV\n\n      - name: Skip Doc tests for windows/macos\n        if: runner.os != \'Linux\'\n        shell: bash\n        run: |\n          echo NO_DOC_TESTS="--no-doc-tests" >> $GITHUB_ENV\n\n      - name: Enable example schema checks on linux\n        if: runner.os != \'Linux\'\n        shell: bash\n        run: |\n          echo EXAMPLE_SCHEMA_CHECKS="--no-example-schema-check" >> $GITHUB_ENV\n\n      - name: Run tests\n        shell: bash\n        run: |\n          cargo xtask run-tests ${{ matrix.backend }} $NO_DOC_TESTS $EXAMPLE_SCHEMA_CHECKS -- --no-fail-fast $FLAGS\n\n      - name: Run diesel_benches\n        if: runner.os == \'Linux\'\n        shell: bash\n        run: cargo +${{ matrix.rust }} test --manifest-path diesel_bench/Cargo.toml --no-default-features --features "${{ matrix.backend }}" --bench benchmarks\n\n  compile_tests:\n    name: Compiletests\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: compile_test-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n\n      - name: Install dependencies\n        run: |\n          sudo apt-get update\n          sudo apt-get -y install libsqlite3-dev libpq-dev libmysqlclient-dev\n\n      - name: Run compile tests\n        shell: bash\n        run: cargo +stable  test --manifest-path diesel_compile_tests/Cargo.toml\n\n  rustfmt_and_clippy:\n    name: Check rustfmt style && run clippy\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n          components: clippy, rustfmt\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: clippy-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n      - name: Fixing up rustup\n        shell: bash\n        run: |\n          rustc --version\n          rustup component add rustfmt clippy\n          which rustc\n          rustup component list\n          cargo fmt --version\n          cargo clippy --version\n\n      - name: Install dependencies\n        run: |\n          sudo apt-get update\n          sudo apt-get -y install libsqlite3-dev libpq-dev libmysqlclient-dev libtirpc-dev\n\n      - uses: taiki-e/install-action@60581cd7025e0e855cebd745379013e286d9c787 # v2.64.2\n        with:\n          tool: typos\n      - name: Set environment variables\n        shell: bash\n        run: |\n          echo "RUSTFLAGS=-D warnings" >> $GITHUB_ENV\n          echo "RUSTDOCFLAGS=-D warnings" >> $GITHUB_ENV\n      - name: Run clippy + rustfmt\n        run: cargo xtask tidy --keep-going\n\n  sqlite_wasm:\n    name: Check sqlite wasm\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n          components: "rust-src,rustfmt"\n          # It seems not to work\n          # targets: "wasm32-unknown-unknown"\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: sqlite_wasm-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n\n      - name: Add wasm32-unknown-unknown target\n        run: rustup target add wasm32-unknown-unknown\n\n      - uses: taiki-e/install-action@60581cd7025e0e855cebd745379013e286d9c787 # v2.64.2\n        with:\n          tool: nextest,wasm-bindgen@0.2.108\n\n      - name: Test unit and integration tests\n        env:\n          DATABASE_URL: ":memory:"\n        run: cargo xtask run-tests --wasm sqlite --no-example-schema-check -- --no-fail-fast  --release\n\n      - name: Test the wasm example\n        env:\n          CARGO_TARGET_WASM32_UNKNOWN_UNKNOWN_RUNNER: wasm-bindgen-test-runner\n        run: cd examples/sqlite/wasm && cargo test --target wasm32-unknown-unknown\n\n  sqlite_bundled:\n    name: Check sqlite bundled + Sqlite with asan\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n          components: "rust-src, rustfmt"\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: sqlite_bundled-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n\n      - name: Test diesel-cli\n        run: cargo +stable test --manifest-path diesel_cli/Cargo.toml --no-default-features --features "sqlite-bundled"\n\n      - name: Run diesel_tests with ASAN enabled\n        env:\n          RUSTC_BOOTSTRAP: 1\n          RUSTFLAGS: -Zsanitizer=address\n          ASAN_OPTIONS: detect_stack_use_after_return=1\n        run: cargo +stable -Z build-std test --manifest-path diesel_tests/Cargo.toml --no-default-features --features "sqlite libsqlite3-sys libsqlite3-sys/bundled libsqlite3-sys/with-asan" --target x86_64-unknown-linux-gnu\n\n      - name: Run diesel tests with ASAN enabled\n        env:\n          RUSTC_BOOTSTRAP: 1\n          RUSTDOCFLAGS: -Zsanitizer=address\n          RUSTFLAGS: -Zsanitizer=address\n          ASAN_OPTIONS: detect_stack_use_after_return=1\n        run: cargo +stable -Z build-std test --manifest-path diesel/Cargo.toml --no-default-features --features "sqlite extras __with_asan_tests" --target x86_64-unknown-linux-gnu\n\n  postgres_bundled:\n    name: Check postgres bundled + Postgres with asan\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n          components: "rust-src, rustfmt"\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: postgres_bundled-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n\n      - name: Install postgres (Linux)\n        run: |\n          sudo apt-get update\n          sudo apt-get install -y libpq-dev postgresql valgrind\n          echo "host    all             all             127.0.0.1/32            md5" > sudo tee -a /etc/postgresql/10/main/pg_hba.conf\n          sudo service postgresql restart && sleep 3\n          sudo -u postgres psql -c "ALTER USER postgres PASSWORD \'postgres\';"\n          sudo service postgresql restart && sleep 3\n          echo "PG_DATABASE_URL=postgres://postgres:postgres@localhost/" >> $GITHUB_ENV\n          echo $PG_DATABASE_URL\n\n      - name: Test diesel-cli\n        run: cargo +stable test --manifest-path diesel_cli/Cargo.toml --no-default-features --features "postgres-bundled"\n\n      - name: Run diesel_tests with ASAN enabled\n        env:\n          RUSTC_BOOTSTRAP: 1\n          RUSTFLAGS: -Zsanitizer=address\n          ASAN_OPTIONS: detect_stack_use_after_return=1\n        run: cargo +stable -Z build-std test --manifest-path diesel_tests/Cargo.toml --no-default-features --features "postgres pq-sys pq-sys/bundled pq-src/with-asan" --target x86_64-unknown-linux-gnu\n\n      - name: Run diesel tests with ASAN enabled\n        env:\n          RUSTC_BOOTSTRAP: 1\n          RUSTDOCFLAGS: -Zsanitizer=address\n          RUSTFLAGS: -Zsanitizer=address\n          ASAN_OPTIONS: detect_stack_use_after_return=1\n        run: cargo +stable -Z build-std test --manifest-path diesel/Cargo.toml --no-default-features --features "postgres extras __with_asan_tests" --target x86_64-unknown-linux-gnu\n\n  mysql_bundled:\n    name: Check mysql bundled + Mysql with asan\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n          components: "rust-src, rustfmt"\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: mysql_bundled-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n      - name: Install Mysql (Linux)\n        run: |\n          sudo apt-get update\n          sudo apt-get -y install libmysqlclient-dev llvm libtirpc-dev\n          sudo systemctl start mysql.service\n          sleep 5\n          mysql -e "create database diesel_test; create database diesel_unit_test; grant all on \\`diesel_%\\`.* to \'root\'@\'localhost\';" -uroot -proot\n          echo "MYSQL_DATABASE_URL=mysql://root:root@127.0.0.1/diesel_test" >> $GITHUB_ENV\n          echo "MYSQL_EXAMPLE_DATABASE_URL=mysql://root:root@127.0.0.1/diesel_example" >> $GITHUB_ENV\n          echo "MYSQL_UNIT_TEST_DATABASE_URL=mysql://root:root@127.0.0.1/diesel_unit_test" >> $GITHUB_ENV\n\n      - name: Test diesel-cli\n        env:\n          RUST_TEST_THREADS: 1\n        run: cargo +stable test --manifest-path diesel_cli/Cargo.toml --no-default-features --features "mysql-bundled"\n\n      - name: Run diesel_tests with ASAN enabled\n        env:\n          RUSTC_BOOTSTRAP: 1\n          RUSTFLAGS: -Zsanitizer=address\n          RUST_TEST_THREADS: 1\n          ASAN_OPTIONS: symbolize=1,detect_stack_use_after_return=1\n          ASAN_SYMBOLIZER_PATH: /usr/bin/llvm-symbolizer\n          LSAN_OPTIONS: suppressions=/tmp/suppr.txt\n        run: |\n          echo "leak:mysql_server_init" > /tmp/suppr.txt\n          cargo +stable -Z build-std test --manifest-path diesel_tests/Cargo.toml --no-default-features --features "mysql mysqlclient-sys mysqlclient-sys/bundled mysqlclient-src/with-asan" --target x86_64-unknown-linux-gnu\n\n      - name: Run diesel tests with ASAN enabled\n        env:\n          RUSTC_BOOTSTRAP: 1\n          RUSTDOCFLAGS: -Zsanitizer=address\n          RUSTFLAGS: -Zsanitizer=address\n          RUST_TEST_THREADS: 1\n          ASAN_OPTIONS: symbolize=1,detect_stack_use_after_return=1\n          ASAN_SYMBOLIZER_PATH: /usr/bin/llvm-symbolizer\n          LSAN_OPTIONS: suppressions=/tmp/suppr.txt\n        run: |\n          echo "leak:mysql_server_init" > /tmp/suppr.txt\n          cargo +stable -Z build-std test --manifest-path diesel/Cargo.toml --no-default-features --features "mysql extras __with_asan_tests" --target x86_64-unknown-linux-gnu\n\n  minimal_rust_version:\n    name: Check Minimal supported rust version (1.88.0)\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: 1.88.0\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: nightly\n      - uses: taiki-e/install-action@60581cd7025e0e855cebd745379013e286d9c787 # v2.64.2\n        with:\n          tool: cargo-hack,cargo-minimal-versions\n      - name: Cache cargo registry\n        uses: Swatinem/rust-cache@779680da715d629ac1d338a641029a2f4372abb5 # v2.8.2\n        with:\n          key: minimal_rust_version-cargo-${{ hashFiles(\'**/Cargo.toml\') }}\n      - name: Install dependencies\n        run: |\n          sudo apt-get update\n          sudo apt-get -y install libsqlite3-dev libpq-dev libmysqlclient-dev\n      - name: Check diesel_derives\n        run: cargo +1.88.0 minimal-versions check -p diesel_derives --features "postgres sqlite mysql 32-column-tables 64-column-tables 128-column-tables without-deprecated with-deprecated r2d2"\n      - name: Check diesel\n        run: cargo +1.88.0 minimal-versions check -p diesel --features "postgres mysql sqlite extras"\n      - name: Check diesel_dynamic_schema\n        run: cargo +1.88.0 minimal-versions check -p diesel-dynamic-schema --all-features\n      - name: Check diesel_migrations\n        run: cargo +1.88.0 minimal-versions check -p diesel_migrations --all-features\n      - name: Check diesel_cli\n        run: cargo +1.88.0 minimal-versions check -p diesel_cli --features "default sqlite-bundled"\n\n  Semver-Checks:\n    name: Run Cargo Semver-Checks\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n      - uses: taiki-e/install-action@60581cd7025e0e855cebd745379013e286d9c787 # v2.64.2\n        with:\n          tool: cargo-semver-checks\n      - name: Run cargo semver-checks\n        run: |\n          cargo xtask semver-checks\n  Sqlite-no-std:\n    name: Sqlite (no-std)\n    runs-on: ubuntu-latest\n    needs: [rustfmt_and_clippy]\n    steps:\n      - uses: actions/checkout@8e8c483db84b4bee98b60c0593521ed34d9990e8 # v6.0.1\n        with:\n          persist-credentials: false\n      - uses: dtolnay/rust-toolchain@f7ccc83f9ed1e5b9c81d8a67d7ad1a747e22a561 # master\n        with:\n          toolchain: stable\n          targets: riscv32imac-unknown-none-elf\n      - name: Install cross compiler\n        run: |\n          curl -L https://github.com/nycu-arclab/riscv32-toolchain/releases/download/v14.2.0/riscv32-unknown-elf-gcc-14.2.0-linux.tar.gz -o riscv32-toolchain-linux.tar.gz\n          tar -xzvf riscv32-toolchain-linux.tar.gz -C /opt\n      - name: Check if diesel builds for no-std targets\n        run: |\n          cd examples/sqlite/embedded\n          rustup target add riscv32imac-unknown-none-elf\n          LIBSQLITE3_FLAGS="-DSQLITE_SMALL_STACK=1 -DSQLITE_THREADSAFE=0 -DSQLITE_OS_OTHER=1 -DSQLITE_OMIT_LOCALTIME=1 -USQLITE_ENABLE_FTS3 -UQLITE_ENABLE_DBSTAT_VTAB -UDSQLITE_ENABLE_JSON1 -USQLITE_ENABLE_FTS5 -USQLITE_ENABLE_STAT4 -DSQLITE_ENABLE_MEMSYS3=1" TARGET_CC=/opt/riscv/bin/riscv32-unknown-elf-gcc cargo build --target riscv32imac-unknown-none-elf\n',
            'diesel/Cargo.toml': '[package]\nname = "diesel"\nversion = "2.3.6"\nlicense = "MIT OR Apache-2.0"\ndescription = "A safe, extensible ORM and Query Builder for PostgreSQL, SQLite, and MySQL"\nreadme = "README.md"\ndocumentation = "https://docs.rs/diesel/"\nhomepage = "https://diesel.rs"\nrepository = "https://github.com/diesel-rs/diesel"\nkeywords = ["orm", "database", "sql"]\ncategories = ["database"]\nedition.workspace = true\nrust-version.workspace = true\ninclude = [\n    "src/**/*.rs",\n    "tests/**/*.rs",\n    "LICENSE-*",\n    "README.md",\n    "src/sqlite/connection/diesel_manage_updated_at.sql",\n    "src/migration/setup_migration_table.sql",\n]\n\n[dependencies]\nbyteorder = { version = "1.0", optional = true }\nchrono = { version = "0.4.20", optional = true, default-features = false, features = ["clock", "std"] }\nlibc = { version = "0.2.0", optional = true }\nmysqlclient-sys = { version = ">=0.2.5, <0.6.0",  optional = true }\nmysqlclient-src = { version = ">=0.1.0, <0.3", optional = true }\npq-sys = { version = ">=0.4.0, <0.8.0", optional = true }\npq-src = { version = "0.3", optional = true }\nquickcheck = { version = "1.0.3", optional = true }\nserde_json = { version = ">=0.8.0, <2.0", optional = true, default-features = false, features = ["alloc"] }\nurl = { version = "2.1.0", optional = true }\npercent-encoding = { version = "2.1.0", optional = true }\nuuid = { version = ">=0.7.0, <2.0.0", optional = true }\nipnetwork = { version = ">=0.12.2, <0.22.0", optional = true }\nipnet = { version = "2.5.0", optional = true }\nnum-bigint = { version = ">=0.2.0, <0.5.0", optional = true }\nnum-traits = { version = "0.2.0", optional = true }\nnum-integer = { version = "0.1.39", optional = true }\nbigdecimal = { version = ">=0.0.13, < 0.5.0", optional = true }\nbitflags = { version = "2.0.0", optional = true }\nr2d2 = { version = ">= 0.8.2, < 0.9.0", optional = true }\nitoa = { version = "1.0.0", optional = true }\ntime = { version = "0.3.9", optional = true, features = ["macros"] }\ndowncast-rs = { version = "2.0.1", default-features = false }\nhashbrown = { version = "0.16", optional = true }\n\n[dependencies.diesel_derives]\nversion = "~2.3.0"\npath = "../diesel_derives"\n\n[target.\'cfg(not(all(target_family = "wasm", target_os = "unknown")))\'.dependencies]\nlibsqlite3-sys = { version = ">=0.17.2, <0.37.0", optional = true, features = ["bundled_bindings"] }\n\n[target.\'cfg(all(target_family = "wasm", target_os = "unknown"))\'.dependencies]\nsqlite-wasm-rs = { version = ">=0.4.0, <0.6.0", optional = true, default-features = false }\n\n[target.\'cfg(all(target_family = "wasm", target_os = "unknown"))\'.dev-dependencies]\n# Something is dependent on it, we use feature to override it.\ngetrandom = { version = "0.4", features = ["wasm_js"] }\ngetrandom_03 = { version = "0.3", features = ["wasm_js"], package = "getrandom" }\nwasm-bindgen-test = "0.3.49"\n\n[dev-dependencies]\ncfg-if = "1"\ndotenvy = "0.15"\nipnetwork = ">=0.12.2, <0.22.0"\nquickcheck = "1.0.3"\ntempfile = "3.10.1"\ndiesel_test_helper = { path = "../diesel_test_helper" }\n\n[features]\ndefault = ["with-deprecated", "32-column-tables", "std"]\nextras = ["chrono", "time", "serde_json", "uuid", "network-address", "numeric", "r2d2"]\nunstable = ["diesel_derives/nightly"]\nlarge-tables = ["32-column-tables"]\nhuge-tables = ["64-column-tables"]\n32-column-tables = ["diesel_derives/32-column-tables"]\n64-column-tables = ["32-column-tables", "diesel_derives/64-column-tables"]\n128-column-tables = ["64-column-tables", "diesel_derives/128-column-tables"]\npostgres = ["dep:pq-sys", "postgres_backend"]\nsqlite-no-std = ["__sqlite-shared", "hashbrown"]\nsqlite = ["__sqlite-shared", "std"]\nmysql = ["dep:mysqlclient-sys", "dep:url", "dep:percent-encoding", "dep:bitflags", "mysql_backend"]\nwithout-deprecated = ["diesel_derives/without-deprecated"]\nwith-deprecated = ["diesel_derives/with-deprecated"]\nnetwork-address = ["dep:ipnetwork", "dep:libc"]\nipnet-address = ["dep:ipnet", "dep:libc"]\nnumeric = ["dep:num-bigint", "dep:bigdecimal", "dep:num-traits", "dep:num-integer", "diesel_derives/numeric"]\npostgres_backend = ["diesel_derives/postgres", "dep:bitflags", "dep:byteorder", "dep:itoa", "std"]\nmysql_backend = ["diesel_derives/mysql", "dep:byteorder", "std"]\nreturning_clauses_for_sqlite_3_35 = ["sqlite"]\ni-implement-a-third-party-backend-and-opt-into-breaking-changes = []\nr2d2 = ["diesel_derives/r2d2", "dep:r2d2"]\nchrono = ["diesel_derives/chrono", "dep:chrono"]\ntime = ["diesel_derives/time", "dep:time"]\nuuid = ["dep:uuid"]\nserde_json = ["dep:serde_json"]\n__sqlite-shared = ["dep:libsqlite3-sys", "dep:sqlite-wasm-rs", "diesel_derives/sqlite", "time?/formatting", "time?/parsing"]\n__with_asan_tests = [\n    "libsqlite3-sys?/bundled",\n    "libsqlite3-sys?/with-asan",\n    "pq-sys?/bundled",\n    "pq-src?/with-asan",\n    "mysqlclient-sys?/bundled",\n    "mysqlclient-src?/with-asan",\n]\nstd = ["serde_json?/std"]\nhashbrown = ["dep:hashbrown"]\n\n[package.metadata.docs.rs]\nfeatures = ["postgres", "mysql", "sqlite", "extras"]\nno-default-features = true\nrustc-args = ["--cfg", "diesel_docs"]\nrustdoc-args = ["--cfg", "diesel_docsrs", "-Z", "unstable-options", "--generate-link-to-definition", "--generate-macro-expansion"]\n\n[lints]\nworkspace = true\n',
            'xtask/src/tests/mod.rs': 'use crate::Backend;\nuse cargo_metadata::{Metadata, MetadataCommand};\nuse std::process::Command;\nuse std::process::Stdio;\n\n#[derive(clap::Args, Debug)]\npub(crate) struct TestArgs {\n    /// Run tests for a specific backend\n    #[clap(default_value_t = Backend::All)]\n    backend: Backend,\n    /// skip the unit/integration tests\n    #[clap(long = "no-integration-tests")]\n    no_integration_tests: bool,\n    /// skip the doc tests\n    #[clap(long = "no-doc-tests")]\n    no_doc_tests: bool,\n    // skip the checks for the example schema setup\n    #[clap(long = "no-example-schema-check")]\n    no_example_schema_check: bool,\n    /// do not abort running if we encounter an error\n    /// while running tests for all backends\n    #[clap(long = "keep-going")]\n    keep_going: bool,\n    // run wasm tests, currently only supports sqlite\n    #[clap(long = "wasm")]\n    wasm: bool,\n    /// additional flags passed to cargo nextest while running\n    /// unit/integration tests.\n    ///\n    /// This is useful for passing custom test filters/arguments\n    ///\n    /// See <https://nexte.st/docs/running/> for details\n    flags: Vec<String>,\n}\n\nimpl TestArgs {\n    pub(crate) fn run(mut self) {\n        let metadata = MetadataCommand::default().exec().unwrap();\n        let success = if matches!(self.backend, Backend::All) {\n            let mut success = true;\n            for backend in Backend::ALL {\n                self.backend = *backend;\n                let result = self.run_tests(&metadata);\n                success = success && result;\n                if !result && !self.keep_going {\n                    break;\n                }\n            }\n            success\n        } else {\n            self.run_tests(&metadata)\n        };\n        if !success {\n            std::process::exit(1);\n        }\n    }\n\n    fn run_tests(&self, metadata: &Metadata) -> bool {\n        let backend_name = self.backend.to_string();\n        println!("Running tests for {backend_name}");\n        let exclude = crate::utils::get_exclude_for_backend(&backend_name, metadata, self.wasm);\n        if std::env::var("DATABASE_URL").is_err() {\n            match self.backend {\n                Backend::Postgres => {\n                    if std::env::var("PG_DATABASE_URL").is_err() {\n                        println!(\n                            "Remember to set `PG_DATABASE_URL` for running the postgres tests"\n                        );\n                    }\n                }\n                Backend::Sqlite => {\n                    if std::env::var("SQLITE_DATABASE_URL").is_err() {\n                        println!(\n                            "Remember to set `SQLITE_DATABASE_URL` for running the sqlite tests"\n                        );\n                    }\n                }\n                Backend::Mysql => {\n                    if std::env::var("MYSQL_DATABASE_URL").is_err()\n                        || std::env::var("MYSQL_UNIT_TEST_DATABASE_URL").is_err()\n                    {\n                        println!(\n                            "Remember to set `MYSQL_DATABASE_URL` and `MYSQL_UNIT_TEST_DATABASE_URL` for running the mysql tests"\n                        );\n                    }\n                }\n                Backend::All => unreachable!(),\n            }\n        }\n        let backend = &self.backend;\n        if matches!(backend, Backend::Postgres | Backend::Mysql | Backend::All if self.wasm) {\n            eprintln!(\n                "Only the sqlite backend supports wasm for now, the current backend is {backend}"\n            );\n            return true;\n        }\n        let url = match backend {\n            Backend::Postgres => std::env::var("PG_DATABASE_URL"),\n            Backend::Sqlite => std::env::var("SQLITE_DATABASE_URL"),\n            Backend::Mysql => std::env::var("MYSQL_DATABASE_URL"),\n            Backend::All => unreachable!(),\n        };\n        let url = url\n            .or_else(|_| std::env::var("DATABASE_URL"))\n            .expect("DATABASE_URL is set for tests");\n\n        if !self.wasm {\n            // run the migrations\n            let mut command = Command::new("cargo");\n            command\n                .args(["run", "-p", "diesel_cli", "--no-default-features", "-F"])\n                .arg(backend.to_string())\n                .args(["--", "migration", "run", "--migration-dir"])\n                .arg(\n                    metadata\n                        .workspace_root\n                        .join("migrations")\n                        .join(backend.to_string()),\n                )\n                .arg("--database-url")\n                .arg(&url);\n            println!("Run database migration via `{command:?}`");\n            let status = command\n                .stdout(Stdio::inherit())\n                .stderr(Stdio::inherit())\n                .status()\n                .unwrap();\n            if !status.success() {\n                eprintln!("Failed to run migrations");\n                return false;\n            }\n        }\n\n        if !self.no_integration_tests {\n            // run the normal tests via nextest\n            let mut command = Command::new("cargo");\n            command\n                .args(["nextest", "run", "--workspace", "--no-default-features"])\n                .current_dir(&metadata.workspace_root)\n                .args(exclude)\n                .arg("-F")\n                .arg(format!("diesel/{backend}"))\n                .args(["-F", "diesel/extras"])\n                .arg("-F")\n                .arg(format!("diesel_derives/{backend}"))\n                .arg("-F")\n                .arg(format!("migrations_macros/{backend}"))\n                .arg("-F")\n                .arg(format!("diesel_migrations/{backend}"))\n                .arg("-F")\n                .arg(format!("diesel_tests/{backend}"))\n                .arg("-F")\n                .arg(format!("diesel-dynamic-schema/{backend}"))\n                .args(&self.flags);\n\n            if matches!(self.backend, Backend::Mysql) {\n                // cannot run mysql tests in parallel\n                command.args(["-j", "1"]);\n            }\n            if self.wasm {\n                command\n                    .env("WASM_BINDGEN_TEST_TIMEOUT", "120")\n                    .env(\n                        "CARGO_TARGET_WASM32_UNKNOWN_UNKNOWN_RUNNER",\n                        "wasm-bindgen-test-runner",\n                    )\n                    .env("RUSTFLAGS", "--cfg getrandom_backend=\\"wasm_js\\"")\n                    .arg("--target")\n                    .arg("wasm32-unknown-unknown");\n            } else {\n                command.arg("-F").arg(format!("diesel_cli/{backend}"));\n            }\n            println!("Running tests via `{command:?}`: ");\n\n            let out = command\n                .stderr(Stdio::inherit())\n                .stdout(Stdio::inherit())\n                .status()\n                .unwrap();\n            if !out.success() {\n                eprintln!("Failed to run integration tests");\n                return false;\n            }\n        } else {\n            println!("Integration tests skipped because `--no-integration-tests` was passed");\n        }\n        if !self.no_doc_tests {\n            let mut command = Command::new("cargo");\n\n            command\n                .current_dir(&metadata.workspace_root)\n                .args([\n                    "test",\n                    "--doc",\n                    "--no-default-features",\n                    "-p",\n                    "diesel",\n                    "-p",\n                    "diesel_derives",\n                    "-p",\n                    "diesel_migrations",\n                    "-p",\n                    "diesel-dynamic-schema",\n                    "-p",\n                    "dsl_auto_type",\n                    "-p",\n                    "diesel_table_macro_syntax",\n                    "-F",\n                    "diesel/extras",\n                ])\n                .arg("-F")\n                .arg(format!("diesel/{backend}"))\n                .arg("-F")\n                .arg(format!("diesel_derives/{backend}"))\n                .arg("-F")\n                .arg(format!("diesel-dynamic-schema/{backend}"));\n            if matches!(backend, Backend::Mysql) {\n                // cannot run mysql tests in parallel\n                command.args(["-j", "1"]);\n            }\n            if self.wasm {\n                command\n                    .env("WASM_BINDGEN_TEST_TIMEOUT", "120")\n                    .env(\n                        "CARGO_TARGET_WASM32_UNKNOWN_UNKNOWN_RUNNER",\n                        "wasm-bindgen-test-runner",\n                    )\n                    .env("RUSTFLAGS", "--cfg getrandom_backend=\\"wasm_js\\"")\n                    .arg("--target")\n                    .arg("wasm32-unknown-unknown");\n            }\n            println!("Running tests via `{command:?}`: ");\n            let status = command\n                .stdout(Stdio::inherit())\n                .stderr(Stdio::inherit())\n                .status()\n                .unwrap();\n            if !status.success() {\n                eprintln!("Failed to run doc tests");\n                return false;\n            }\n        } else {\n            println!("Doc tests are skipped because `--no-doc-tests` was passed");\n        }\n\n        if !self.no_example_schema_check {\n            let examples = metadata\n                .workspace_root\n                .join("examples")\n                .join(backend.to_string());\n            let temp_dir = if matches!(backend, Backend::Sqlite) {\n                Some(tempfile::tempdir().unwrap())\n            } else {\n                None\n            };\n            let mut fail = false;\n            for p in metadata\n                .workspace_packages()\n                .into_iter()\n                .filter(|p| p.manifest_path.starts_with(&examples))\n            {\n                let example_root = p.manifest_path.parent().unwrap();\n                if example_root.join("migrations").exists() {\n                    let db_url = if matches!(backend, Backend::Sqlite) {\n                        temp_dir\n                            .as_ref()\n                            .unwrap()\n                            .path()\n                            .join(&p.name)\n                            .display()\n                            .to_string()\n                    } else {\n                        // it\'s a url with the structure postgres://[user:password@host:port/database?options\n                        // we parse it manually as we don\'t want to pull in the url crate with all\n                        // its features\n                        let (start, end) = url.rsplit_once(\'/\').unwrap();\n                        let query = end.split_once(\'?\').map(|(_, q)| q);\n\n                        let mut url = format!("{start}/{}", p.name);\n                        if let Some(query) = query {\n                            url.push(\'?\');\n                            url.push_str(query);\n                        }\n                        url\n                    };\n\n                    let mut command = Command::new("cargo");\n                    command\n                        .current_dir(example_root)\n                        .args(["run", "-p", "diesel_cli", "--no-default-features", "-F"])\n                        .arg(backend.to_string())\n                        .args(["--", "database", "reset", "--locked-schema"])\n                        .env("DATABASE_URL", db_url);\n                    println!(\n                        "Check schema for example `{}` ({example_root}) with command `{command:?}`",\n                        p.name,\n                    );\n                    let status = command.status().unwrap();\n                    if !status.success() {\n                        fail = true;\n                        eprintln!("Failed to check example schema for `{}`", p.name);\n                        if !self.keep_going {\n                            return false;\n                        }\n                    }\n                }\n            }\n            if fail {\n                return false;\n            }\n        } else {\n            println!(\n                "Example schema check is skipped because `--no-example-schema-check` was passed"\n            );\n        }\n\n        true\n    }\n}\n',
        }
